def get_ctx(k, default=""):
    r = q_one("SELECT valor FROM contexto WHERE clave=?", (k,))
    return r["valor"] if r else default

def set_ctx(k, v):
    if q_one("SELECT clave FROM contexto WHERE clave=?", (k,)):
        q_exec("UPDATE contexto SET valor=? WHERE clave=?", (str(v), k))
    else:
        q_exec("INSERT INTO contexto(clave,valor) VALUES(?,?)", (k, str(v)))

def tabs():
    # Admin trabaja con panel vertical fijo; no necesita panel horizontal.
    if session.get("rol") == "ADMIN":
        return []
    return [
        ("ventas", "Venta", "ventas"),
        ("pos", "POS rápido", "pos_rapido"),
        ("pedidos", "Pedido", "pedidos"),
        ("catalogo", "Catálogo", "catalogo_admin"),
        ("cierre", "Cierre", "cierre"),
    ]

def page(content, active="dashboard"):
    return render_template_string(
        BASE_HTML,
        content=content,
        active=active,
        title=APP_TITLE,
        subtitle=APP_SUBTITLE,
        brand=BRAND,
        tabs=tabs(),
        money=money,
    )

def select_options(rows, value_key="id", text_key="nombre", selected=None):
    out = []
    for r in rows:
        val = str(r[value_key])
        sel = "selected" if selected is not None and str(selected) == val else ""
        out.append(f'<option value="{val}" {sel}>{r[text_key]}</option>')
    return "".join(out)

# =========================
# LÓGICA NEGOCIO
# =========================
def descontar_receta(producto_id, cantidad_producto):
    for r in q_all("SELECT * FROM recetas WHERE producto_id=?", (producto_id,)):
        q_exec(
            "UPDATE insumos SET stock=COALESCE(stock,0)-? WHERE id=?",
            (float(r["cantidad"] or 0) * float(cantidad_producto or 0), r["insumo_id"]),
        )

def descontar_producto(producto_id, cantidad):
    q_exec("UPDATE productos SET stock=COALESCE(stock,0)-? WHERE id=?", (float(cantidad or 0), producto_id))
    descontar_receta(producto_id, cantidad)

def asegurar_cliente(nombre, telefono='', direccion='', referencia=''):
    nombre = up(nombre or 'CLIENTE GENERAL')
    telefono = clean(telefono)
    direccion = up(direccion)
    referencia = up(referencia)
    if not nombre or nombre == 'CLIENTE GENERAL':
        return
    r = q_one("SELECT id FROM clientes WHERE UPPER(nombre)=UPPER(?) OR (telefono<>'' AND telefono=?) LIMIT 1", (nombre, telefono))
    if r:
        q_exec("UPDATE clientes SET telefono=COALESCE(NULLIF(?,''),telefono), direccion=COALESCE(NULLIF(?,''),direccion), referencia=COALESCE(NULLIF(?,''),referencia) WHERE id=?", (telefono, direccion, referencia, r['id']))
    else:
        q_exec("INSERT INTO clientes(nombre,telefono,direccion,referencia,activo) VALUES(?,?,?,?,1)", (nombre, telefono, direccion, referencia))

def agregar_item_a_pedido(pedido_id, producto_id, cantidad=1):
    prod = q_one("SELECT * FROM productos WHERE id=? AND activo=1", (producto_id,))
    if not prod:
        return False, 'Producto no válido.'
    cantidad = int(float(cantidad or 1))
    precio = float(prod['precio'] or 0)
    subtotal = precio * cantidad
    q_exec("INSERT INTO pedido_detalle(pedido_id,producto_id,producto,cantidad,precio,total) VALUES(?,?,?,?,?,?)", (pedido_id, producto_id, prod['nombre'], cantidad, precio, subtotal))
    descontar_producto(producto_id, cantidad)
    total_items = q_one("SELECT COALESCE(SUM(total),0) t FROM pedido_detalle WHERE pedido_id=?", (pedido_id,))['t']
    desc = q_one("SELECT COALESCE(descuento,0) d FROM pedidos WHERE id=?", (pedido_id,))['d']
    q_exec("UPDATE pedidos SET subtotal=?, total=max(?-?,0), estado=CASE WHEN estado='PAGADO' THEN 'PENDIENTE' ELSE estado END, pagado=CASE WHEN pagado='SI' THEN 'NO' ELSE pagado END WHERE id=?", (total_items, total_items, desc, pedido_id))
    return True, 'Ítem agregado al pedido inicial.'

def crear_venta_desde_pedido(pedido_id, metodo_pago="EFECTIVO"):
    p = q_one("SELECT * FROM pedidos WHERE id=?", (pedido_id,))
    if not p:
        return None
    if p["pagado"] == "SI":
        return None
    vid = q_exec(
        "INSERT INTO ventas(fecha,hora,pedido_id,cliente,servicio,metodo_pago,subtotal,descuento,total,usuario,estado,sucursal_id) VALUES(?,?,?,?,?,?,?,?,?,?,?,?)",
        (today(), hour(), pedido_id, p["cliente"], p["servicio"], metodo_pago, p["subtotal"], p["descuento"], p["total"], session.get("user", ""), "PAGADO", session.get("sucursal_id",1)),
    )
    for d in q_all("SELECT * FROM pedido_detalle WHERE pedido_id=?", (pedido_id,)):
        q_exec(
            "INSERT INTO venta_detalle(venta_id,producto_id,producto,cantidad,precio,total) VALUES(?,?,?,?,?,?)",
            (vid, d["producto_id"], d["producto"], d["cantidad"], d["precio"], d["total"]),
        )
        # Stock ya se descuenta al crear/agregar el pedido; no duplicar descuento al cobrar.
    q_exec("UPDATE pedidos SET pagado='SI', estado='PAGADO' WHERE id=?", (pedido_id,))
    q_exec(
        "INSERT INTO caja(fecha,hora,tipo,concepto,monto,usuario,venta_id,sucursal_id) VALUES(?,?,?,?,?,?,?,?)",
        (today(), hour(), "INGRESO", f"VENTA PEDIDO {p['codigo']}", p["total"], session.get("user", ""), vid, session.get("sucursal_id",1)),
    )
    log_event("VENTA", f"Pedido cobrado {p['codigo']}")
    return vid

