@app.route("/ventas", methods=["GET", "POST"])
@login_required
def ventas():
    if request.method == "POST":
        accion = request.form.get("accion", "guardar_pedido")
        if accion == "importar_productos" and "archivo" in request.files:
            if not is_admin():
                flash("Carga de inicio de día restringida: solo administrador.", "error")
                return redirect(url_for("ventas"))
            count = importar_productos(request.files["archivo"])
            flash(f"Carga inicio día completada: {count} productos actualizados.", "ok")
            return redirect(url_for("ventas"))
        producto_id = int(request.form.get("producto_id") or 0)
        cantidad = int(float(request.form.get("cantidad") or 1))
        if accion in ("guardar_pedido", "pos_rapido", "agregar_a_pedido"):
            prod = q_one("SELECT * FROM productos WHERE id=? AND activo=1", (producto_id,))
            if not prod:
                flash("Selecciona un producto válido.", "error")
                return redirect(url_for("ventas"))
            pedido_existente = int(request.form.get("pedido_existente_id") or 0)
            if accion == "agregar_a_pedido" or pedido_existente:
                if not pedido_existente:
                    flash("Selecciona el pedido inicial para agregar el producto.", "error")
                    return redirect(url_for("ventas"))
                ok, msg = agregar_item_a_pedido(pedido_existente, producto_id, cantidad)
                flash(msg, "ok" if ok else "error")
                return redirect(url_for("pedidos"))
            descuento = float(request.form.get("descuento") or 0)
            precio = float(prod["precio"] or 0)
            subtotal = precio * cantidad
            total = max(subtotal - descuento, 0)
            codigo = "PED-" + now().strftime("%Y%m%d-%H%M%S")
            cliente = up(request.form.get("cliente") or "CLIENTE GENERAL")
            telefono = clean(request.form.get("telefono"))
            direccion = up(request.form.get("direccion"))
            referencia = up(request.form.get("referencia"))
            asegurar_cliente(cliente, telefono, direccion, referencia)
            pedido_id = q_exec("INSERT INTO pedidos(codigo,fecha,hora,mesa,cliente,telefono,direccion,referencia,servicio,metodo_pago,subtotal,descuento,total,estado,pagado,usuario,observacion,sucursal_id) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)", (codigo, today(), hour(), request.form.get("mesa", ""), cliente, telefono, direccion, referencia, request.form.get("servicio", "SALÓN"), request.form.get("metodo_pago", "EFECTIVO"), subtotal, descuento, total, "PENDIENTE", "NO", session.get("user"), "", session.get("sucursal_id",1)))
            q_exec("INSERT INTO pedido_detalle(pedido_id,producto_id,producto,cantidad,precio,total) VALUES(?,?,?,?,?,?)", (pedido_id, producto_id, prod["nombre"], cantidad, precio, total))
            descontar_producto(producto_id, cantidad)
            log_event("PEDIDO", f"Creado {codigo} - {prod['nombre']}")
            flash(f"Pedido guardado: {prod['nombre']} x {cantidad}.", "ok")
            return redirect(url_for("pos_rapido") if accion == "pos_rapido" else url_for("ventas"))
        if accion == "cobrar_ticket":
            pedido_id = int(request.form.get("pedido_id") or 0)
            metodo = request.form.get("metodo_pago", "EFECTIVO")
            vid = crear_venta_desde_pedido(pedido_id, metodo)
            if vid and metodo in ("YAPE", "PLIN", "TRANSFERENCIA"):
                return redirect(url_for("pago_qr", pedido_id=pedido_id, metodo=metodo))
            flash("Pedido cobrado y ticket generado." if vid else "No se pudo cobrar: verifica que el pedido exista y no esté pagado.", "ok" if vid else "error")
            return redirect(url_for("ventas"))
    buscar_prod = clean(request.args.get("buscar", ""))
    solo_disp = request.args.get("disponible", "") == "1"
    cat_filtro = clean(request.args.get("categoria", ""))
    where = ["activo=1"]
    params = []
    if buscar_prod:
        like = f"%{buscar_prod.upper()}%"
        where.append("(UPPER(nombre) LIKE ? OR UPPER(categoria) LIKE ? OR UPPER(codigo) LIKE ?)")
        params += [like, like, like]
    if solo_disp:
        where.append("COALESCE(stock,0)>0")
    if cat_filtro:
        where.append("UPPER(categoria)=UPPER(?)")
        params.append(cat_filtro)
    productos = q_all("SELECT * FROM productos WHERE " + " AND ".join(where) + " ORDER BY categoria, CASE WHEN stock>0 THEN 0 ELSE 1 END, nombre", tuple(params))
    categorias = q_all("SELECT DISTINCT categoria FROM productos WHERE activo=1 AND COALESCE(categoria,'')<>'' ORDER BY categoria")
    opts_prod = "".join(f'<option value="{p["id"]}">{p["codigo"] or p["id"]} · {p["nombre"]} · {money(p["precio"])} · Stock {int(float(p["stock"] or 0))}</option>' for p in productos)
    tr_prod = "".join(f'<tr class="{"row-ok" if float(r["stock"] or 0)>0 else "row-bad"}"><td>{r["codigo"]}</td><td><b>{r["nombre"]}</b></td><td>{r["categoria"]}</td><td>{money(r["precio"])}</td><td>{int(float(r["stock"] or 0))}</td><td>{"DISPONIBLE" if float(r["stock"] or 0)>0 else "SIN STOCK"}</td></tr>' for r in productos[:150]) or '<tr><td colspan="6">Sin productos.</td></tr>'
    pedidos_pend = q_all("SELECT p.*, COALESCE((SELECT GROUP_CONCAT(producto || ' x' || CAST(cantidad AS INT), ' + ') FROM pedido_detalle d WHERE d.pedido_id=p.id),'') productos FROM pedidos p WHERE p.pagado='NO' ORDER BY p.id DESC LIMIT 80")
    opts_ped = '<option value="">Selecciona pedido abierto</option>' + "".join(f'<option value="{p["id"]}">{p["codigo"]} · {p["cliente"]} · {p["productos"]} · {money(p["total"])} · {p["estado"]}</option>' for p in pedidos_pend)
    cat_opts = '<option value="">Todas las categorías</option>' + ''.join(f'<option value="{c["categoria"]}" {"selected" if cat_filtro==c["categoria"] else ""}>{c["categoria"]}</option>' for c in categorias)
    cat_links = '<div class="category-bar"><a class="' + ('' if cat_filtro else 'on') + '" href="' + url_for('ventas') + '#catalogo-productos">TODOS</a>' + ''.join(f'<a class="{"on" if cat_filtro==c["categoria"] else ""}" href="{url_for("ventas", categoria=c["categoria"], disponible="1" if solo_disp else "")}#catalogo-productos">{c["categoria"]}</a>' for c in categorias) + '</div>'
    clientes = q_all("SELECT * FROM clientes WHERE activo=1 ORDER BY nombre LIMIT 250")
    cliente_options = "".join(f'<option value="{c["nombre"]}">{c["telefono"]} {c["direccion"]}</option>' for c in clientes)
    detalle = q_all("SELECT d.*,p.codigo FROM pedido_detalle d JOIN pedidos p ON p.id=d.pedido_id ORDER BY d.id DESC LIMIT 40")
    tr_det = "".join(f'<tr><td>{r["codigo"]}</td><td><b>{r["producto"]}</b></td><td>{int(float(r["cantidad"] or 0))}</td><td>{money(r["precio"])}</td><td>{money(r["total"])}</td></tr>' for r in detalle) or '<tr><td colspan="5">Sin detalle.</td></tr>'
    pos_cards = ""
    for p in productos[:24]:
        img_row = q_one("SELECT imagen FROM catalogo_publico WHERE UPPER(titulo)=UPPER(?) AND activo=1 ORDER BY destacado DESC,id DESC LIMIT 1", (p['nombre'],))
        img_html = f"<img src='{url_for('static', filename=img_row['imagen'])}' alt='{p['nombre']}'>" if img_row and img_row['imagen'] else ""
        pos_cards += f"""<form method='post' class='pos-card-form'><input type='hidden' name='accion' value='pos_rapido'><input type='hidden' name='producto_id' value='{p['id']}'><input type='hidden' name='cantidad' value='1'><input type='hidden' name='cliente' value='CLIENTE GENERAL'><input type='hidden' name='servicio' value='SALÓN'><input type='hidden' name='metodo_pago' value='EFECTIVO'><button class='pos-product' type='submit'>{img_html}<b>{p['nombre']}</b><span>{money(p['precio'])}</span><small>SKU {p['codigo'] or p['id']} · Stock {int(float(p['stock'] or 0))}</small></button></form>"""
    load_day_html = ""
    if is_admin():
        load_day_html = f"""<div class='panel load-day-panel'><div class='section-title'>📥 Carga de inicio de día</div><div class='hint-card'>Solo ADMIN: importa Excel/CSV para actualizar productos, precios y stock antes de iniciar ventas.</div><br><form method='post' enctype='multipart/form-data' class='actions'><input type='hidden' name='accion' value='importar_productos'><input type='file' name='archivo' accept='.xlsx,.csv' style='max-width:420px'><button class='btn-warning'>📥 Cargar día / importar Excel productos</button><a class='btn' href='{url_for('plantilla_inventario')}'>📄 Descargar plantilla</a></form></div>"""
    html = f"""
    <div class='panel'><div class='section-title'>➕ Agregar producto a pedido inicial</div><div class='hint-card'>Busca el pedido abierto del cliente y agrega gaseosa, pollo, pizza u otro producto. El importe sube en el mismo pedido y el detalle queda disgregado por ítem.</div><form method='post' class='clean-grid'><input type='hidden' name='accion' value='agregar_a_pedido'><div><label>Pedido inicial / cliente</label><select name='pedido_existente_id' required>{opts_ped}</select></div><div><label>Producto a agregar</label><select name='producto_id' required>{opts_prod}</select></div><div><label>Cantidad</label><input name='cantidad' type='number' min='1' step='1' value='1'></div><button class='btn-success'>Agregar al mismo pedido</button></form></div>
    <div class='panel'><div class='section-title'>🧾 Nueva venta / pedido</div><br><form method='post'><input type='hidden' name='accion' value='guardar_pedido'><datalist id='clientes_list'>{cliente_options}</datalist><div class='clean-grid-4'><div><label>Mesa</label><select name='mesa'><option></option><option>MESA 1</option><option>MESA 2</option><option>MESA 3</option><option>MESA 4</option><option>MESA 5</option><option>MESA 6</option></select></div><div><label>Tipo servicio</label><select name='servicio'><option>SALÓN</option><option>DELIVERY</option><option>RECOJO</option></select></div><div><label>Cliente</label><input name='cliente' list='clientes_list' placeholder='Buscar o escribir cliente'></div><div><label>Teléfono</label><input name='telefono' placeholder='Celular'></div><div><label>Dirección</label><input name='direccion' placeholder='Solo para delivery'></div><div><label>Referencia</label><input name='referencia' placeholder='Referencia'></div><div><label>Producto</label><select name='producto_id'>{opts_prod}</select></div><div><label>Cantidad</label><input name='cantidad' type='number' min='1' step='1' value='1'></div><div><label>Método pago</label><select name='metodo_pago'><option>EFECTIVO</option><option>YAPE</option><option>PLIN</option><option>TARJETA</option><option>TRANSFERENCIA</option></select></div><div><label>Descuento</label><input name='descuento' type='number' min='0' step='1' value='0'></div></div><br><div class='actions'><button class='primary'>Guardar pedido</button><button type='reset'>Limpiar venta</button><a class='btn' href='{url_for('inventario') if is_admin() else url_for('catalogo_admin')}'>Nuevo producto</a><a class='btn' href='{url_for('pedidos')}'>Ver pedidos</a></div></form></div>
    <div class='panel'><div class='box-title'>Cobro rápido</div><br><form method='post' class='actions'><input type='hidden' name='accion' value='cobrar_ticket'><select name='pedido_id' style='max-width:680px'>{opts_ped}</select><select name='metodo_pago' style='max-width:220px'><option>EFECTIVO</option><option>YAPE</option><option>PLIN</option><option>TARJETA</option><option>TRANSFERENCIA</option></select><button class='btn-success'>Cobrar y ticket / QR</button></form></div>
    <div class='panel filter-sticky' id='filtros-venta'><form method='get' action='{url_for('ventas')}#catalogo-productos' class='catalog-filter-actions'><div><label>Buscar producto</label><input name='buscar' value='{buscar_prod}' placeholder='Buscar producto por nombre, código o categoría'></div><div><label>Categoría</label><select name='categoria' onchange='this.form.submit()'>{cat_opts}</select></div><button name='disponible' value='1'>✅ Filtrar disponibles</button><a class='btn' href='{url_for('ventas')}#catalogo-productos'>Limpiar</a></form></div>
    <div class='panel' id='catalogo-productos'><div class='section-title'>🍽️ Catálogo de productos</div><div class='table-wrap small'><table><thead><tr><th>Código</th><th>Producto</th><th>Categoría</th><th>Precio</th><th>Stock</th><th>Estado</th></tr></thead><tbody>{tr_prod}</tbody></table></div></div>{load_day_html}
    <div class='panel'><div class='section-title'>🧩 Últimos ítems registrados</div><div class='table-wrap small'><table><thead><tr><th>Pedido</th><th>Producto</th><th>Cantidad</th><th>Precio</th><th>Subtotal</th></tr></thead><tbody>{tr_det}</tbody></table></div></div>"""
    return page(html, "ventas")


@app.route("/pos_rapido", methods=["GET", "POST"])
@login_required
def pos_rapido():
    if request.method == "POST":
        producto_id = int(request.form.get("producto_id") or 0)
        cantidad = int(float(request.form.get("cantidad") or 1))
        prod = q_one("SELECT * FROM productos WHERE id=? AND activo=1", (producto_id,))
        if not prod:
            flash("Selecciona un producto válido.", "error")
            return redirect(url_for("pos_rapido"))
        descuento = float(request.form.get("descuento") or 0)
        precio = float(prod["precio"] or 0)
        subtotal = precio * cantidad
        total = max(subtotal - descuento, 0)
        codigo = "PED-" + now().strftime("%Y%m%d-%H%M%S")
        cliente = up(request.form.get("cliente") or "CLIENTE GENERAL")
        telefono = clean(request.form.get("telefono"))
        direccion = up(request.form.get("direccion"))
        referencia = up(request.form.get("referencia"))
        servicio = request.form.get("servicio", "SALÓN")
        metodo = request.form.get("metodo_pago", "EFECTIVO")
        asegurar_cliente(cliente, telefono, direccion, referencia)
        pedido_id = q_exec("INSERT INTO pedidos(codigo,fecha,hora,mesa,cliente,telefono,direccion,referencia,servicio,metodo_pago,subtotal,descuento,total,estado,pagado,usuario,observacion,sucursal_id) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)", (codigo, today(), hour(), request.form.get("mesa", ""), cliente, telefono, direccion, referencia, servicio, metodo, subtotal, descuento, total, "PENDIENTE", "NO", session.get("user"), "POS RÁPIDO", session.get("sucursal_id",1)))
        q_exec("INSERT INTO pedido_detalle(pedido_id,producto_id,producto,cantidad,precio,total) VALUES(?,?,?,?,?,?)", (pedido_id, producto_id, prod["nombre"], cantidad, precio, total))
        descontar_producto(producto_id, cantidad)
        log_event("POS", f"POS rápido {codigo} - {cliente} - {prod['nombre']}")
        flash(f"POS guardado: {cliente} · {prod['nombre']} x {cantidad}.", "ok")
        return redirect(url_for("pos_rapido"))

    buscar_prod = clean(request.args.get("buscar", ""))
    cat_filtro = clean(request.args.get("categoria", ""))
    where = ["activo=1"]
    params = []
    if buscar_prod:
        like = f"%{buscar_prod.upper()}%"
        where.append("(UPPER(nombre) LIKE ? OR UPPER(categoria) LIKE ? OR UPPER(codigo) LIKE ?)")
        params += [like, like, like]
    if cat_filtro:
        where.append("UPPER(categoria)=UPPER(?)")
        params.append(cat_filtro)
    productos = q_all("SELECT * FROM productos WHERE " + " AND ".join(where) + " ORDER BY categoria, CASE WHEN stock>0 THEN 0 ELSE 1 END, nombre", tuple(params))
    categorias = q_all("SELECT DISTINCT categoria FROM productos WHERE activo=1 AND COALESCE(categoria,'')<>'' ORDER BY categoria")
    clientes = q_all("SELECT * FROM clientes WHERE activo=1 ORDER BY nombre LIMIT 250")
    cliente_options = "".join(f'<option value="{c["nombre"]}">{c["telefono"]} {c["direccion"]}</option>' for c in clientes)
    cat_opts = '<option value="">Todas las categorías</option>' + ''.join(f'<option value="{c["categoria"]}" {"selected" if cat_filtro==c["categoria"] else ""}>{c["categoria"]}</option>' for c in categorias)
    mini_cards = ""
    list_cards = ""
    for idx, p in enumerate(productos[:80]):
        img_row = q_one("SELECT imagen FROM catalogo_publico WHERE UPPER(titulo)=UPPER(?) AND activo=1 ORDER BY destacado DESC,id DESC LIMIT 1", (p['nombre'],))
        if img_row and img_row['imagen'] and img_row['imagen'] != 'toro_logo.png':
            img_src = url_for('static', filename=img_row['imagen'])
            img_tag = f"<img src='{img_src}' alt='{p['nombre']}'>"
        else:
            img_tag = "<div class='pos-food-placeholder'>🍽️</div>"
        hidden = f"""
          <input type='hidden' name='producto_id' value='{p['id']}'>
          <input type='hidden' name='cantidad' value='1'>
          <input type='hidden' name='cliente' class='pos_cliente_hidden' value='CLIENTE GENERAL'>
          <input type='hidden' name='telefono' class='pos_telefono_hidden' value=''>
          <input type='hidden' name='mesa' class='pos_mesa_hidden' value=''>
          <input type='hidden' name='servicio' class='pos_servicio_hidden' value='SALÓN'>
          <input type='hidden' name='metodo_pago' class='pos_pago_hidden' value='EFECTIVO'>"""
        if idx < 6:
            mini_cards += f"""<form method='post' class='pos-card-form keep-pos-form'>{hidden}<button class='pos-mini-card' type='submit'><div class='pos-mini-img'>{img_tag}</div><b>{p['nombre']}</b><span>{money(p['precio'])}</span><small>Add Cart</small></button></form>"""
        list_cards += f"""<form method='post' class='pos-list-form keep-pos-form'>{hidden}<button class='pos-list-card' type='submit'><div class='pos-list-img'><span class='heart'>♥</span>{img_tag}</div><div><b>{p['nombre']}</b><p>{p['categoria'] or 'Producto'} · SKU {p['codigo'] or p['id']} · Stock {int(float(p['stock'] or 0))}</p><span>{money(p['precio'])}</span></div><em class='add-pill'>Add Cart</em></button></form>"""
    if not mini_cards:
        mini_cards = "<div class='hint-card'>No hay productos para mostrar.</div>"
    if not list_cards:
        list_cards = "<div class='hint-card'>No hay productos para la búsqueda.</div>"
    cat_links = '<div class="category-bar"><a class="' + ('' if cat_filtro else 'on') + '" href="' + url_for('pos_rapido') + '">TODOS</a>' + ''.join(f'<a class="{"on" if cat_filtro==c["categoria"] else ""}" href="{url_for("pos_rapido", categoria=c["categoria"])}">{c["categoria"]}</a>' for c in categorias) + '</div>'
    html = f"""
    <div class="mobile-active-title">⚡ POS rápido</div>
    <div class="pos-app-shell">
      <div class="pos-app-header">
        <div style="display:flex;align-items:center;gap:14px"><img src="{url_for('static', filename='toro_logo.png')}" alt="EL TORO"><div><h2>POS rápido</h2><p>Diseño claro premium: busca, toca y vende al instante</p></div></div>
        <div style="font-size:26px;color:#94a3b8">☰</div>
      </div>
      <div class="pos-client-panel-dark">
        <datalist id="clientes_pos_list">{cliente_options}</datalist>
        <form method="get" class="pos-client-grid">
          <div><label>Cliente</label><input id="pos_cliente" list="clientes_pos_list" placeholder="CLIENTE GENERAL / nombre"></div>
          <div><label>Teléfono / DNI</label><input id="pos_telefono" placeholder="Celular o DNI"></div>
          <div><label>Mesa</label><select id="pos_mesa"><option></option><option>MESA 1</option><option>MESA 2</option><option>MESA 3</option><option>MESA 4</option><option>MESA 5</option><option>MESA 6</option></select></div>
          <div><label>Servicio</label><select id="pos_servicio"><option>SALÓN</option><option>RECOJO</option><option>DELIVERY</option></select></div>
          <div><label>Pago</label><select id="pos_pago"><option>EFECTIVO</option><option>YAPE</option><option>PLIN</option><option>TARJETA</option><option>TRANSFERENCIA</option></select></div>
        </form>
      </div>
      <div class="pos-phone-layout">
        <div class="pos-phone pos-phone-left">
          <div class="phone-top"><span>←</span><span>☰</span></div>
          <div class="pos-hero-food"><h1>El Toro<br>POS Rápido</h1></div>
          <div class="pos-category-title">Food Category</div>
          <div class="pos-mini-grid">{mini_cards[:999999]}</div>
          <div class="pos-category-title">Food Category</div>
          <div class="pos-mini-grid">{mini_cards}</div>
        </div>
        <div class="pos-phone">
          <div class="phone-top"><span>←</span><span>☰</span></div>
          <form method="get" action="{url_for('pos_rapido')}" class="pos-search-bar">
            <input name="buscar" value="{buscar_prod}" placeholder="Search From Here">
            <select name="categoria" onchange="this.form.submit()">{cat_opts}</select>
            <button>🔎</button><a href="{url_for('pos_rapido')}">⚙️</a>
          </form>
          {cat_links}
          <div class="pos-food-list">{list_cards}</div>
        </div>
      </div>
    </div>
    <script>
      function syncPOSClient(){{
        const cliente=(document.getElementById('pos_cliente').value||'CLIENTE GENERAL').trim() || 'CLIENTE GENERAL';
        const telefono=(document.getElementById('pos_telefono').value||'').trim();
        const mesa=document.getElementById('pos_mesa').value||'';
        const servicio=document.getElementById('pos_servicio').value||'SALÓN';
        const pago=document.getElementById('pos_pago').value||'EFECTIVO';
        document.querySelectorAll('.pos_cliente_hidden').forEach(e=>e.value=cliente);
        document.querySelectorAll('.pos_telefono_hidden').forEach(e=>e.value=telefono);
        document.querySelectorAll('.pos_mesa_hidden').forEach(e=>e.value=mesa);
        document.querySelectorAll('.pos_servicio_hidden').forEach(e=>e.value=servicio);
        document.querySelectorAll('.pos_pago_hidden').forEach(e=>e.value=pago);
        try{{sessionStorage.setItem('pos_cliente',cliente);sessionStorage.setItem('pos_telefono',telefono);sessionStorage.setItem('pos_mesa',mesa);sessionStorage.setItem('pos_servicio',servicio);sessionStorage.setItem('pos_pago',pago);}}catch(e){{}}
      }}
      ['pos_cliente','pos_telefono','pos_mesa','pos_servicio','pos_pago'].forEach(id=>{{const el=document.getElementById(id); if(el) el.addEventListener('input',syncPOSClient); if(el) el.addEventListener('change',syncPOSClient);}});
      window.addEventListener('load',function(){{try{{document.getElementById('pos_cliente').value=sessionStorage.getItem('pos_cliente')||'';document.getElementById('pos_telefono').value=sessionStorage.getItem('pos_telefono')||'';document.getElementById('pos_mesa').value=sessionStorage.getItem('pos_mesa')||'';document.getElementById('pos_servicio').value=sessionStorage.getItem('pos_servicio')||'SALÓN';document.getElementById('pos_pago').value=sessionStorage.getItem('pos_pago')||'EFECTIVO';}}catch(e){{}} syncPOSClient();}});
      document.querySelectorAll('.keep-pos-form').forEach(f=>f.addEventListener('submit',syncPOSClient));
    </script>
    """
    return page(html, "pos")

@app.route("/pedidos", methods=["GET", "POST"])
@login_required
def pedidos():
    if request.method == "POST":
        accion = request.form.get("accion")
        pedido_id = int(request.form.get("pedido_id") or 0)
        if not pedido_id:
            flash("Selecciona un pedido.", "error")
            return redirect(url_for("pedidos"))
        pedido_actual = q_one("SELECT estado,pagado FROM pedidos WHERE id=?", (pedido_id,))
        if accion == "estado":
            if pedido_actual and (pedido_actual["estado"] in ("ENTREGADO", "PAGADO") or pedido_actual["pagado"] == "SI"):
                flash("Este pedido ya fue entregado o pagado; no se puede cambiar desde el desplegable.", "error")
                return redirect(url_for("pedidos"))
            nuevo = request.form.get("estado", "PENDIENTE")
            if nuevo == "PAGADO":
                flash("Para pagar usa el botón Marcar pagado; así se registra caja y venta.", "error")
            else:
                q_exec("UPDATE pedidos SET estado=? WHERE id=?", (nuevo, pedido_id))
                flash("Estado actualizado.", "ok")
        elif accion == "pagado":
            if pedido_actual and (pedido_actual["pagado"] == "SI" or pedido_actual["estado"] == "PAGADO"):
                flash("Este pedido ya está pagado; no aparece en el cobro pendiente.", "error")
                return redirect(url_for("pedidos"))
            crear_venta_desde_pedido(pedido_id, request.form.get("metodo_pago", "EFECTIVO"))
            flash("Pedido marcado como pagado.", "ok")
        elif accion == "quitar_item":
            if pedido_actual and (pedido_actual["estado"] in ("ENTREGADO", "PAGADO") or pedido_actual["pagado"] == "SI"):
                flash("No se puede quitar ítems de un pedido entregado o pagado.", "error")
                return redirect(url_for("pedidos"))
            item_id = int(request.form.get("item_id") or 0)
            if item_id:
                q_exec("DELETE FROM pedido_detalle WHERE id=? AND pedido_id=?", (item_id, pedido_id))
                total = q_one("SELECT COALESCE(SUM(total),0) t FROM pedido_detalle WHERE pedido_id=?", (pedido_id,))["t"]
                q_exec("UPDATE pedidos SET subtotal=?, total=max(?-COALESCE(descuento,0),0) WHERE id=?", (total, total, pedido_id))
                flash("Item retirado del pedido.", "ok")
        elif accion == "limpiar":
            q_exec("DELETE FROM pedido_detalle WHERE pedido_id=?", (pedido_id,))
            q_exec("DELETE FROM pedidos WHERE id=?", (pedido_id,))
            flash("Pedido eliminado.", "ok")
        return redirect(url_for("pedidos"))

    estado = request.args.get("estado", "TODOS")
    sucid = session.get("sucursal_id", 1)
    base_sql = "SELECT p.*, COALESCE((SELECT GROUP_CONCAT(producto || ' x' || CAST(cantidad AS INT), ' + ') FROM pedido_detalle d WHERE d.pedido_id=p.id),'') productos FROM pedidos p"
    if is_admin():
        rows = q_all(base_sql + " ORDER BY p.id DESC LIMIT 200") if estado == "TODOS" else q_all(base_sql + " WHERE p.estado=? ORDER BY p.id DESC LIMIT 200", (estado,))
    else:
        rows = q_all(base_sql + " WHERE COALESCE(p.sucursal_id,1)=? ORDER BY p.id DESC LIMIT 200", (sucid,)) if estado == "TODOS" else q_all(base_sql + " WHERE COALESCE(p.sucursal_id,1)=? AND p.estado=? ORDER BY p.id DESC LIMIT 200", (sucid, estado))
    # Listas separadas para evitar operaciones incorrectas:
    # - Estado: solo pedidos NO entregados y NO pagados.
    # - Cobro: solo pedidos abiertos/no pagados.
    # - Quitar ítem: solo pedidos editables, no entregados ni pagados.
    pedidos_estado = [r for r in rows if (r["estado"] not in ("ENTREGADO", "PAGADO") and r["pagado"] != "SI")]
    pedidos_cobro = [r for r in rows if (r["pagado"] != "SI" and r["estado"] != "PAGADO")]
    pedidos_editables_ids = {r["id"] for r in pedidos_estado}

    def pedido_label(r):
        cliente = r["cliente"] or "CLIENTE GENERAL"
        productos = r["productos"] or "Sin ítems"
        return f'{cliente} · {r["codigo"]} · {productos} · {r["estado"]} · {money(r["total"])}'

    opts_estado = '<option value="">Selecciona pedido pendiente por cliente o código</option>' + "".join(
        f'<option value="{r["id"]}">{pedido_label(r)}</option>' for r in pedidos_estado
    )
    opts_cobro = '<option value="">Selecciona pedido abierto por cliente o código</option>' + "".join(
        f'<option value="{r["id"]}">{pedido_label(r)}</option>' for r in pedidos_cobro
    )
    selected_first = (pedidos_cobro[0]["id"] if pedidos_cobro else (pedidos_estado[0]["id"] if pedidos_estado else 0))
    detalles = q_all("SELECT d.*,p.codigo,p.cliente,p.estado,p.pagado FROM pedido_detalle d JOIN pedidos p ON p.id=d.pedido_id ORDER BY d.id DESC LIMIT 120")
    detalles_editables = [r for r in detalles if r["pedido_id"] in pedidos_editables_ids]
    item_opts = '<option value="">Selecciona ítem editable</option>' + "".join(
        f'<option value="{r["id"]}">#{r["id"]} · {r["cliente"] or "CLIENTE GENERAL"} · {r["codigo"]} · {r["producto"]} · Cant. {int(float(r["cantidad"] or 0))}</option>' for r in detalles_editables
    )
    tr_items = "".join(
        f'<tr><td>{r["id"]}</td><td>{r["codigo"]}</td><td><b>{r["producto"]}</b></td><td>{int(float(r["cantidad"] or 0))}</td><td>{money(r["precio"])}</td><td>{money(r["total"])}</td></tr>'
        for r in detalles
    ) or '<tr><td colspan="6">Sin detalle de ítems.</td></tr>'
    total_abierto = sum(float(r["total"] or 0) for r in rows if r["pagado"] == "NO")
    pendientes = sum(1 for r in rows if r["estado"] not in ("PAGADO","ENTREGADO"))
    resumen_cards = f"<div class='pedido-resumen'><div class='pedido-card'><b>{len(rows)}</b><br>Pedidos encontrados</div><div class='pedido-card'><b>{pendientes}</b><br>Pendientes de cocina</div><div class='pedido-card'><b>{money(total_abierto)}</b><br>Importe abierto</div></div>"
    trs = "".join(f'<tr><td>{r["id"]}</td><td>{r["codigo"]}</td><td>{r["fecha"]}</td><td>{r["hora"]}</td><td>{r["mesa"]}</td><td>{r["cliente"]}</td><td><b class="pedido-prod-text">{r["productos"] or "Sin ítems"}</b></td><td>{r["servicio"]}</td><td><span class="badge warn">{r["estado"]}</span></td><td>{money(r["total"])}</td><td>{r["pagado"]}</td></tr>' for r in rows) or '<tr><td colspan="11">Sin pedidos.</td></tr>'
    chips = "".join(f'<div class="item-chip"><b>{r["producto"]}</b><span>{r["codigo"]} · {r["cliente"]}</span><br>Cant. {int(float(r["cantidad"] or 0))} · {money(r["precio"])} · <b>{money(r["total"])}</b></div>' for r in detalles) or '<div class="hint-card">Sin detalle de ítems.</div>'
    html = f'''
    <div class="mobile-active-title">🚚 Pedidos</div>
    <div class="panel"><div class="section-title">🚚 Control de pedidos / cocina</div>{resumen_cards}
      <form method="get" class="clean-grid"><div><label>Filtrar por estado</label><select name="estado"><option>TODOS</option><option>PENDIENTE</option><option>PREPARACIÓN</option><option>LISTO</option><option>ENTREGADO</option></select></div><button>Refrescar</button><a class="btn" href="{url_for('ventas')}">Nuevo pedido</a></form><br>
      <form method="post" class="pedido-actions smart-pedido-form"><div><label>Pedido pendiente / cliente</label><input class="pedido-search" placeholder="Buscar por nombre, código o producto"><select name="pedido_id" class="pedido-select">{opts_estado}</select><small class="muted">No muestra entregados ni pagados.</small></div><div><label>Cambiar a estado</label><select name="estado"><option>PREPARACIÓN</option><option>LISTO</option><option>ENTREGADO</option></select></div><button name="accion" value="estado" class="btn-success">Actualizar estado</button></form><br>
      <form method="post" class="pedido-actions smart-pedido-form"><div><label>Pedido para cobrar</label><input class="pedido-search" placeholder="Buscar por nombre, código o producto"><select name="pedido_id" class="pedido-select">{opts_cobro}</select><small class="muted">Solo pedidos no pagados.</small></div><div><label>Método pago</label><select name="metodo_pago"><option>EFECTIVO</option><option>YAPE</option><option>PLIN</option><option>TARJETA</option></select></div><div class="actions"><button name="accion" value="pagado" class="btn-success">Marcar pagado</button><button name="accion" value="limpiar" class="btn-danger" onclick="return confirm('¿Eliminar pedido completo?')">Eliminar pedido</button><a class="btn" href="{url_for('ticket', pedido_id=selected_first)}">Imprimir ticket</a></div></form><br>
      <form method="post" class="pedido-actions-2 smart-pedido-form"><div><label>Pedido editable</label><input class="pedido-search" placeholder="Buscar por nombre, código o producto"><select name="pedido_id" class="pedido-select">{opts_estado}</select><small class="muted">No muestra entregados ni pagados.</small></div><div><label>Ítem del pedido</label><select name="item_id">{item_opts}</select></div><button name="accion" value="quitar_item" class="btn-warning">➖ Quitar ítem</button></form>
      <script>
      document.querySelectorAll('.smart-pedido-form').forEach(function(form){{
        const input=form.querySelector('.pedido-search');
        const select=form.querySelector('.pedido-select');
        if(!input||!select) return;
        const original=[...select.options].map(o=>({{value:o.value,text:o.text}}));
        input.addEventListener('input',function(){{
          const q=input.value.toLowerCase().trim();
          const current=select.value;
          select.innerHTML='';
          original.forEach(function(o,i){{
            if(i===0 || !q || o.text.toLowerCase().includes(q)){{
              const opt=document.createElement('option'); opt.value=o.value; opt.text=o.text; select.appendChild(opt);
            }}
          }});
          if([...select.options].some(o=>o.value===current)) select.value=current;
          else if(select.options.length>1) select.selectedIndex=1;
        }});
      }});
      </script>
    </div>
    <div class="panel"><div class="section-title">📋 Listado de pedidos</div><div class="table-wrap"><table><thead><tr><th>ID</th><th>Código</th><th>Fecha</th><th>Hora</th><th>Mesa</th><th>Cliente</th><th>Productos</th><th>Servicio</th><th>Estado</th><th>Total</th><th>Pagado</th></tr></thead><tbody>{trs}</tbody></table></div></div>
    <div class="panel"><div class="section-title">🧾 Detalle de ítems</div><div class="table-wrap detalle-table-simple"><table><thead><tr><th>Pedido ID</th><th>Código</th><th>Producto</th><th>Cantidad</th><th>Precio</th><th>Subtotal</th></tr></thead><tbody>{tr_items}</tbody></table></div></div>'''
    return page(html, "pedidos")

@app.route("/ticket/<int:pedido_id>")
@login_required
def ticket(pedido_id):
    p = q_one("SELECT * FROM pedidos WHERE id=?", (pedido_id,)) if pedido_id else q_one("SELECT * FROM pedidos ORDER BY id DESC LIMIT 1")
    if not p:
        return "Sin pedido"
    det = q_all("SELECT * FROM pedido_detalle WHERE pedido_id=?", (p["id"],))
    lines = ["EL TORO RESTAURANT GRILL", "TICKET", f"Pedido: {p['codigo']}", f"Fecha: {p['fecha']} {p['hora']}", f"Cliente: {p['cliente']}", "-" * 32]
    for d in det:
        lines.append(f"{d['cantidad']} x {d['producto']} {money(d['total'])}")
    lines += ["-" * 32, f"TOTAL: {money(p['total'])}"]
    bio = BytesIO("\n".join(lines).encode("utf-8"))
    return send_file(bio, as_attachment=True, download_name=f"ticket_{p['codigo']}.txt", mimetype="text/plain")


@app.route('/pago_qr/<int:pedido_id>/<metodo>')
@login_required
def pago_qr(pedido_id, metodo):
    p = q_one('SELECT * FROM pedidos WHERE id=?', (pedido_id,))
    if not p:
        flash('Pedido no encontrado.', 'error')
        return redirect(url_for('ventas'))
    data = f"EL TORO RESTAURANT GRILL|PEDIDO:{p['codigo']}|METODO:{metodo}|MONTO:{float(p['total'] or 0):.2f}|CLIENTE:{p['cliente']}"
    if QRCODE_OK:
        bio = BytesIO()
        img = qrcode.make(data)
        img.save(bio, format='PNG')
        qr_src = 'data:image/png;base64,' + base64.b64encode(bio.getvalue()).decode('ascii')
    else:
        qr_src = url_for('static', filename='toro_logo.png')
    html = f'''<div class="panel payment-qr-card"><div class="section-title">💳 QR de pago {metodo}</div><p class="hint-card">Muestra este QR al cliente para lectura de pago. Contiene pedido, método y monto. Para conciliación automática real se puede conectar luego con API bancaria/Yape Empresa/Plin.</p><img src="{qr_src}" alt="QR pago"><h2>{p['codigo']}</h2><h1 style="color:#ff1744">{money(p['total'])}</h1><p><b>Cliente:</b> {p['cliente']} · <b>Método:</b> {metodo}</p><div class="actions" style="justify-content:center"><a class="btn-primary" href="{url_for('ticket', pedido_id=pedido_id)}">Imprimir ticket</a><a class="btn" href="{url_for('ventas')}">Volver a ventas</a></div></div>'''
    return page(html, 'ventas')

