@app.route("/admin", methods=["GET", "POST"])
@login_required
@admin_required
def admin():
    if request.method == "POST":
        accion = request.form.get("accion")
        if accion == "sucursal":
            nombre = up(request.form.get("nombre"))
            if nombre:
                q_exec("INSERT OR IGNORE INTO sucursales(nombre,activo) VALUES(?,1)", (nombre,))
                flash("Sucursal registrada.", "ok")
        elif accion == "usuario":
            usuario = clean(request.form.get("usuario"))
            clave = clean(request.form.get("clave"))
            nombre = up(request.form.get("nombre"))
            rol = request.form.get("rol", "VENDEDOR")
            sucursal_id = int(request.form.get("sucursal_id") or 1)
            if rol not in ("ADMIN", "VENDEDOR"):
                rol = "VENDEDOR"
            if usuario and clave:
                q_exec("INSERT OR REPLACE INTO usuarios(usuario,nombre,clave_hash,clave_plain,rol,activo,sucursal_id) VALUES(?,?,?,?,?,1,?)", (usuario, nombre, generate_password_hash(clave), clave, rol, sucursal_id))
                flash("Usuario guardado y enlazado a sucursal.", "ok")
        elif accion == "desactivar_usuario":
            usuario = clean(request.form.get("usuario"))
            if usuario and usuario != session.get("user"):
                q_exec("UPDATE usuarios SET activo=0 WHERE usuario=?", (usuario,))
                log_event("USUARIO DESACTIVADO", usuario)
                flash("Usuario desactivado correctamente.", "ok")
        elif accion == "activar_usuario":
            usuario = clean(request.form.get("usuario"))
            if usuario and usuario != session.get("user"):
                q_exec("UPDATE usuarios SET activo=1 WHERE usuario=?", (usuario,))
                log_event("USUARIO REACTIVADO", usuario)
                flash("Usuario reactivado correctamente.", "ok")
        elif accion == "eliminar_usuario":
            usuario = clean(request.form.get("usuario"))
            if usuario and usuario != session.get("user"):
                q_exec("DELETE FROM usuarios WHERE usuario=?", (usuario,))
                log_event("USUARIO ELIMINADO", usuario)
                flash("Usuario eliminado definitivamente.", "ok")
        elif accion == "sembrar":
            init_db()
            flash("Demo sembrada / verificada.", "ok")
        return redirect(url_for("admin"))
    sucursales = q_all("SELECT * FROM sucursales ORDER BY nombre")
    usuarios = q_all("SELECT u.id,u.usuario,u.nombre,u.rol,u.activo,u.clave_plain,COALESCE(s.nombre,'Sucursal Principal') sucursal FROM usuarios u LEFT JOIN sucursales s ON s.id=u.sucursal_id ORDER BY u.usuario")
    suc_opts = ''.join(f'<option value="{s["id"]}">{s["nombre"]}</option>' for s in sucursales)
    tr_s = "".join(f'<tr><td>{s["id"]}</td><td>{s["nombre"]}</td><td>{s["activo"]}</td></tr>' for s in sucursales)
    tr_u = ""
    for u in usuarios:
        clave_visible = u["clave_plain"] or ""
        if u["usuario"] == session.get("user"):
            accion = "<span class='badge warn'>Usuario actual</span>"
        else:
            usuario_safe = str(u['usuario']).replace("'", "&#39;")
            if int(u['activo'] or 0) == 1:
                estado_btn = f"""<form method='post'><input type='hidden' name='accion' value='desactivar_usuario'><input type='hidden' name='usuario' value='{usuario_safe}'><button class='btn-disable btn-mini' onclick="return confirm('¿Desactivar este usuario? Podrás conservar su historial.')">Desactivar</button></form>"""
            else:
                estado_btn = f"""<form method='post'><input type='hidden' name='accion' value='activar_usuario'><input type='hidden' name='usuario' value='{usuario_safe}'><button class='btn-restore btn-mini' onclick="return confirm('¿Reactivar este usuario?')">Reactivar</button></form>"""
            borrar_btn = f"""<form method='post'><input type='hidden' name='accion' value='eliminar_usuario'><input type='hidden' name='usuario' value='{usuario_safe}'><button class='btn-delete btn-mini' onclick="return confirm('¿Eliminar definitivamente este usuario? Esta acción no se puede deshacer.')">Eliminar</button></form>"""
            accion = "<div class='admin-action-stack'>" + estado_btn + borrar_btn + "</div>"
        tr_u += f"""
        <tr>
          <td>{u['usuario']}</td><td>{u['nombre']}</td><td>{u['rol']}</td><td>{u['sucursal']}</td>
          <td><div class='pass-box'><input id='pass_{u['id']}' type='password' value='{clave_visible}' readonly><button type='button' onclick='togglePass({u['id']})'>👁</button></div></td>
          <td>{'ACTIVO' if int(u['activo'] or 0)==1 else 'INACTIVO'}</td><td>{accion}</td>
        </tr>"""
    html = f"""
    <div class="role-note">✅ Administración multi-sucursal: crea sucursales, enlaza vendedores a cada local y reserva la carga del día para ADMIN.</div>
    <div class="admin-super-grid">
      <div class="panel"><div class="section-title">👤 Crear / actualizar usuario</div>
        <form method="post" class="admin-form-grid">
          <input type="hidden" name="accion" value="usuario">
          <div><label>Usuario</label><input name="usuario" required placeholder="ej: vendedor1"></div>
          <div><label>Nombre</label><input name="nombre" placeholder="Nombre completo"></div>
          <div><label>Clave</label><input name="clave" type="password" required placeholder="Clave"></div>
          <div><label>Rol</label><select name="rol"><option>VENDEDOR</option><option>ADMIN</option></select></div>
          <div><label>Sucursal asignada</label><select name="sucursal_id">{suc_opts}</select></div>
          <button class="primary" style="grid-column:1/-1">Guardar usuario</button>
        </form>
      </div>
      <div class="panel"><div class="section-title">🏬 Sucursales / locales</div>
        <form method="post" class="admin-form-grid"><input type="hidden" name="accion" value="sucursal"><div><label>Nueva sucursal</label><input name="nombre" placeholder="Ej. El Toro Centro"></div><button class="btn-green">Registrar sucursal</button><button name="accion" value="sembrar" class="btn-orange">Sembrar demo</button></form>
        <br><div class="hint-card">Pensado para cadena: sucursales, usuarios por rol, turnos, caja y reportes por local.</div>
      </div>
    </div>
    <div class="food-card-grid">
      <div class="food-card"><div class="thumb">🔐</div><b>Roles claros</b><small>Admin controla todo; vendedores trabajan ventas/pedidos/cierre.</small></div>
      <div class="food-card"><div class="thumb">🏪</div><b>Sucursales</b><small>Base para reportes por local y turnos.</small></div>
      <div class="food-card"><div class="thumb">📱</div><b>Celular</b><small>Botones grandes y navegación tipo app.</small></div>
    </div><br>
    <div class="admin-table-grid">
      <div class="panel"><div class="section-title">🏬 Sucursales creadas</div><div class="table-wrap small"><table><thead><tr><th>ID</th><th>Sucursal</th><th>Activo</th></tr></thead><tbody>{tr_s}</tbody></table></div></div>
      <div class="panel admin-users-panel same-place-anchor" id="usuarios-admin"><div class="section-title">👥 Usuarios creados</div><div class="keep-position-note">Ahora puedes desactivar, reactivar o eliminar usuarios sin perder tu posición en pantalla.</div><div class="table-wrap small"><table><thead><tr><th>Usuario</th><th>Nombre</th><th>Rol</th><th>Sucursal</th><th>Clave</th><th>Activo</th><th>Acciones</th></tr></thead><tbody>{tr_u}</tbody></table></div></div>
    </div>
    <div class="panel"><div class="section-title">📌 Resumen funcional</div><textarea class="report-box" readonly>NEGOCIO EL TORO - NIVEL DIOS UI/UX

MEJORAS ACTIVAS:
- Branding rojo intenso y logo El Toro.
- Administración limpia y visible, sin tablas escondidas.
- Vista celular modo app.
- Roles: ADMIN completo; usuarios operativos limitados.
- Preparado para restaurante, pizzería y cadena con sucursales.

Base actual: {DB_PATH}</textarea></div>
    """
    return page(html, "admin")


